# Core type definitions - classes, interfaces, structs, enums

# Status enum for tracking operation results
enum Status:
    PENDING = 0
    PROCESSING = 1
    COMPLETED = 2
    FAILED = 3

# Interface for items that can be priced
interface IPriceable:
    @abstract
    def get_price(self) -> float:
        ...

    @abstract
    def get_name(self) -> str:
        ...

# Interface for items that can be described
interface IDescribable:
    @abstract
    def get_description(self) -> str:
        ...

# Product struct (value type)
struct Product:
    name: str
    base_price: float
    quantity: int

    def __init__(self, name: str, base_price: float, quantity: int):
        self.name = name
        self.base_price = base_price
        self.quantity = quantity

    def total_value(self) -> float:
        return self.base_price * float(self.quantity)

# Base class for inventory items
class InventoryItem:
    sku: str
    status: Status

    def __init__(self, sku: str):
        self.sku = sku
        self.status = Status.PENDING

    @virtual
    def mark_processed(self) -> None:
        self.status = Status.PROCESSING

    @virtual
    def get_display_label(self) -> str:
        return f"SKU:{self.sku}"

