# Handlers that implement interfaces and inherit from base classes
from models import IPriceable, IDescribable, InventoryItem, Status

# Concrete class implementing interfaces and inheriting
class PricedInventoryItem(InventoryItem, IPriceable, IDescribable):
    price: float
    description: str

    def __init__(self, sku: str, price: float, description: str):
        super().__init__(sku)
        self.price = price
        self.description = description

    @override
    def mark_processed(self) -> None:
        super().mark_processed()
        self.status = Status.COMPLETED

    @override
    def get_display_label(self) -> str:
        return f"{super().get_display_label()}|${self.price}"

    # Interface implementations
    def get_price(self) -> float:
        return self.price

    def get_name(self) -> str:
        return f"Item({self.sku})"

    def get_description(self) -> str:
        return self.description

# Simple handler for status transitions
class StatusHandler:
    items_processed: int

    def __init__(self):
        self.items_processed = 0

    def process_item(self, item: InventoryItem) -> str:
        old_status: Status = item.status
        item.mark_processed()
        self.items_processed += 1
        return f"{old_status.name}|{item.status.name}"

