# Utility functions and helpers
from models import Product, Status

def calculate_discount(base: float, percent: int) -> float:
    return base * (1.0 - float(percent) / 100.0)

def format_product_info(p: Product) -> str:
    return f"{p.name}:{p.total_value()}"

def get_status_priority(s: Status) -> int:
    return s.value

# Factory function
def create_product(name: str, price: float, qty: int) -> Product:
    return Product(name, price, qty)
